package com.example.socialauth

import android.content.Intent
import android.os.Bundle
import android.view.View
import androidx.appcompat.app.AppCompatActivity
import com.facebook.*
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions
import com.google.android.gms.common.api.ApiException
import com.google.android.material.snackbar.Snackbar

class LoginActivity : AppCompatActivity() {

    private lateinit var facebookCallbackManager: CallbackManager
    private lateinit var googleSignInClient: GoogleSignInClient

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        setupFacebookLogin()
        setupGoogleLogin()
    }

    private fun setupFacebookLogin() {
        facebookCallbackManager = CallbackManager.Factory.create()
        val fbButton: com.facebook.login.widget.LoginButton = findViewById(R.id.btn_facebook_login)
        fbButton.setPermissions(listOf("email", "public_profile"))
        fbButton.registerCallback(facebookCallbackManager, object : FacebookCallback<LoginResult> {
            override fun onSuccess(result: LoginResult) {
                handleFacebookAccessToken(result.accessToken)
            }

            override fun onCancel() { }

            override fun onError(error: FacebookException) {
                showError(error.message)
            }
        })
    }

    private fun setupGoogleLogin() {
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestIdToken(SocialAuthConfig.GOOGLE_CLIENT_ID)
            .requestEmail()
            .build()
        googleSignInClient = GoogleSignIn.getClient(this, gso)

        findViewById<View>(R.id.btn_google_sign_in).setOnClickListener {
            startActivityForResult(googleSignInClient.signInIntent, RC_GOOGLE_SIGN_IN)
        }
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        facebookCallbackManager.onActivityResult(requestCode, resultCode, data)

        if (requestCode == RC_GOOGLE_SIGN_IN) {
            val task = GoogleSignIn.getSignedInAccountFromIntent(data)
            try {
                val account = task.getResult(ApiException::class.java)
                onGoogleLoginSuccess(account.idToken)
            } catch (e: ApiException) {
                showError(e.message)
            }
        }
    }

    private fun handleFacebookAccessToken(token: AccessToken) {
        // TODO: Use token.token to authenticate with your backend
        startMain()
    }

    private fun onGoogleLoginSuccess(idToken: String?) {
        // TODO: Use idToken + SocialAuthConfig.GOOGLE_CLIENT_SECRET to authenticate with your backend
        startMain()
    }

    private fun startMain() {
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }

    private fun showError(message: String?) {
        Snackbar.make(findViewById(android.R.id.content), message ?: "Unknown error", Snackbar.LENGTH_LONG).show()
    }

    companion object {
        private const val RC_GOOGLE_SIGN_IN = 1001
    }
}

